-- #### 1.2 COPY INTO statement
-- - see the documentation [here](https://learn.microsoft.com/en-us/sql/t-sql/statements/copy-into-transact-sql?view=fabric) 
-- - Used to ingest data from ADLS Gen2 (only, currently)
-- - Can be used with Trusted Workspace Access 
-- - Can also include DATETIME column types (passing in the DATEFORMAT parameter) 
-- - [recent support added](https://blog.fabric.microsoft.com/en-GB/blog/17468//) for more granular permissions, allowing users with general Read Permissions, but INSERT per with the COPY INTO, not assessed in DP-700, but maybe useful to know.
-- - Also ONE OF THE FASTEST METHODS TO INGEST DATA INTO FABRIC!  

-- CELL ********************

-- COPY INTO (from ADLS Gen2)
COPY INTO [dbo].[contacts]
FROM 'https://dojostorage.blob.core.windows.net/dojostorage/hubspot_contacts_test.csv'
WITH (
    FILE_TYPE = 'CSV', 
    FIRSTROW = 2
);

