-- ## Section 2: Keys 
-- - Primary Key constraints 
-- - Surrogate keys (for dimensional modeling)

-- MARKDOWN ********************

-- #### 2.1 Primary Key constraints
-- - you can add primary key constraints to existing tables with ALTER TABLE... ADD CONSTRAINT. 
-- - In Fabric DW, it's always NONCLUSTERED, and NOT ENFORCED. 
-- 
-- **Why set PK constraints if they are not enforced?** Helps with query planning and optimization (under the hood), plus useful for documentation. 


-- CELL ********************

CREATE TABLE [dbo].[products] 
(
    product_surr_key INT NOT NULL, 
    product_id INT,
    product_name VARCHAR(100) 
); 

ALTER TABLE [dbo].[products] ADD CONSTRAINT PK_Products PRIMARY KEY NONCLUSTERED ([product_surr_key]) NOT ENFORCED;


-- METADATA ********************

-- META {
-- META   "language": "sql",
-- META   "language_group": "sqldatawarehouse"
-- META }

-- CELL ********************

-- let's check the Primary Key has been applied succesfully
SELECT CONSTRAINT_NAME, CONSTRAINT_TYPE
FROM INFORMATION_SCHEMA.TABLE_CONSTRAINTS
WHERE TABLE_NAME='products';

-- METADATA ********************

-- META {
-- META   "language": "sql",
-- META   "language_group": "sqldatawarehouse"
-- META }

-- CELL ********************

-- look, I can insert two values, each with a Primary Key of 1 - it doesn't stop me. 
INSERT INTO [dbo].[products]
VALUES (1, 10002, 'Trampoline Small'), (1, 10003, 'Trampoline Large')

-- METADATA ********************

-- META {
-- META   "language": "sql",
-- META   "language_group": "sqldatawarehouse"
-- META }

-- CELL ********************

-- we can view the Products table and see that we have two Primary Keys with the same value (NOT ENFORCED)

SELECT * FROM [dbo].[products]

-- METADATA ********************

-- META {
-- META   "language": "sql",
-- META   "language_group": "sqldatawarehouse"
-- META }

-- CELL ********************

-- let's delete the second item  
DELETE FROM [dbo].[products] 
WHERE [product_name] = 'Trampoline Large'

-- METADATA ********************

-- META {
-- META   "language": "sql",
-- META   "language_group": "sqldatawarehouse"
-- META }

-- MARKDOWN ********************

-- #### 2.2 Surrogate Key generation
-- WHY? Most source systems have a 'natural' key, for example a 'ProductID' which is a unique identifier in the source system, generated in the source system.
-- 
-- In can be a good practice to also generate what's called a surrogate key in your analysis environment (Fabric). 
-- 
-- A suurrogate key is a unique identifier that does not depend on any data in the source system, it is generated in Fabric. 
-- 
-- It is especially useful if you are aiming for an SCF Type 2 Dimensional Modelling pattern, when you might have multiple rows (history) for a single ProductID (natural key). In this instance, a generated surrogate key acts as the unique identifier that is then used in your Dimension Tables, and used when generating your Fact tables also. 
-- 
-- Currently, Identity columns are not supported within the Fabric Data Warehouse, so there are a few workarounds. This is a popular one, provided by Microsoft:

-- CELL ********************

-- in this block we are setting up an insert, using a 'temporary' STAGING table 
-- temporary tables are not currently supported (but on roadmap for Q1 2025)

CREATE SCHEMA [staging];
GO;
CREATE TABLE [staging].[updated_products] 
(
    product_id INT NOT NULL, -- FROM SOURCE SYSTEM 
    product_name VARCHAR(100) 
); 

INSERT INTO [staging].[updated_products] 
VALUES (10003,'New Trampoline Model')

-- METADATA ********************

-- META {
-- META   "language": "sql",
-- META   "language_group": "sqldatawarehouse"
-- META }

-- CELL ********************

-- generate new surrogate keys
DECLARE @MaxProductSurrKey AS INT;

IF EXISTS(SELECT * FROM [dbo].[products])
    SET @MaxProductSurrKey = (SELECT MAX([product_surr_key]) FROM [dbo].[products]);
ELSE
    SET @MaxProductSurrKey = 0;

-- insert the Inserted records, in SCD Type 2 format
INSERT INTO [dbo].[products]
SELECT
    @MaxProductSurrKey + ROW_NUMBER() OVER(ORDER BY (SELECT NULL)) AS [product_surr_key],
    [src].[product_id],
    [src].[product_name]
    
FROM [staging].[updated_products] AS [src]


-- METADATA ********************

-- META {
-- META   "language": "sql",
-- META   "language_group": "sqldatawarehouse"
-- META }

-- CELL ********************

SELECT * FROM dbo.products

-- METADATA ********************

-- META {
-- META   "language": "sql",
-- META   "language_group": "sqldatawarehouse"
-- META }

