-- Create some new tables Customers & Orders  
CREATE TABLE [dbo].[dim_customers] (
    customer_id INT,
    first_name VARCHAR(50),
    last_name VARCHAR(50)
);

CREATE TABLE [dbo].[fact_orders] (
    order_id INT,
    customer INT,  -- This column links to Customers.customer_id
    amount DECIMAL(10, 2)
);

-- insert some data into them
INSERT INTO [dbo].[dim_customers] (customer_id, first_name, last_name)
VALUES 
    (1, 'Alice', 'Smith'),
    (2, 'Bob', 'Jones'),
    (3, 'Charlie', 'Brown'),
    (4, NULL, 'Miller');

INSERT INTO [dbo].[fact_orders] (order_id, customer, amount)
VALUES 
    (101, 1, 200.00),
    (102, 1, 150.50),
    (103, 2, 300.25),
    (104, 4, 34.75);


-- METADATA ********************

-- META {
-- META   "language": "sql",
-- META   "language_group": "sqldatawarehouse"
-- META }

-- MARKDOWN ********************

-- Preview the data:

-- CELL ********************

SELECT * FROM [dbo].[dim_customers]

SELECT * FROM [dbo].[fact_orders] 

