-- META {
-- META   "language": "sql",
-- META   "language_group": "sqldatawarehouse"
-- META }

-- MARKDOWN ********************

-- #### LEFT Join
-- "All from the LEFT hand side of the join, and matching from the right hand side" 

-- CELL ********************

SELECT
    C.[customer_id], 
    C.[first_name], 
    Orders.[amount]
FROM 
    [dbo].[dim_customers] AS C
LEFT JOIN 
    [dbo].[fact_orders] AS Orders ON C.customer_id = Orders.customer;


-- METADATA ********************

-- META {
-- META   "language": "sql",
-- META   "language_group": "sqldatawarehouse"
-- META }

-- MARKDOWN ********************

-- #### INNER Join

-- CELL ********************

SELECT 
    C.[customer_id], 
    C.[first_name], 
    Orders.[amount]
FROM 
    [dbo].[dim_customers] AS C
INNER JOIN 
    [dbo].[fact_orders] AS Orders ON C.[customer_id] = Orders.[customer];


-- METADATA ********************

-- META {
-- META   "language": "sql",
-- META   "language_group": "sqldatawarehouse"
-- META }

-- MARKDOWN ********************

-- #### FULL OUTER join

-- CELL ********************

SELECT 
    C.[customer_id],
    C.[first_name],
    Orders.[amount]
FROM 
    [dbo].[dim_customers] C
FULL OUTER JOIN 
    [dbo].[fact_orders] Orders ON C.[customer_id] = Orders.[customer];


-- METADATA ********************

-- META {
-- META   "language": "sql",
-- META   "language_group": "sqldatawarehouse"
-- META }

