-- ## Section 5: Implementing Granular Security in a Fabric Data Warehouse 
-- 
-- Let's very briefly recap the syntax for granular security in the Fabric Data Warehouse. 
-- 
-- Please note: thecode shown below is just for you to revise the syntax, the code won't run stand-alone in this notebook. 
-- 
-- For a more thorough explanation/ walkthrough, go through the following exercises: 
-- - [AD003 🔶 Implement RLS in a Data Warehouse](https://www.skool.com/fabricdojo/classroom/478d51f3?md=0ad0234b148b4641a0c6ad245d1e8097)
-- - [AD004 🔶 Implement OLS and CLS in DW](https://www.skool.com/fabricdojo/classroom/478d51f3?md=fda3d3f17e2647f3a4dd4d1fa383bd2a)
-- - [AD005 🔶 Implement Dynamic Data Masking](https://www.skool.com/fabricdojo/classroom/478d51f3?md=ea728fbcb91841328330e8b3b5934d8e)
-- 
-- 
-- #### Implementing Row-Level Security

-- MARKDOWN ********************


-- CELL ********************

-- STEP 1 Create Schema (optional)
CREATE SCHEMA Security;

-- STEP 2: CREATE table-valued FUNCTION 
CREATE FUNCTION Security.f_FilterRowsForLoggedInUser(@SalesRep AS varchar(100))
    RETURNS TABLE
WITH SCHEMABINDING
AS
    RETURN SELECT 1 AS f_FilterResult
WHERE @SalesRep = USER_NAME();
GO;

-- STEP 3: CreateSecurity Policy (tying the function to a specific table)
CREATE SECURITY POLICY SalesRowFilterPolicy
ADD FILTER PREDICATE Security.f_FilterRowsForLoggedInUser(SalesRep)
ON Sales.Orders
WITH (STATE = ON);


-- METADATA ********************

-- META {
-- META   "language": "sql",
-- META   "language_group": "sqldatawarehouse"
-- META }

-- MARKDOWN ********************

-- #### Implement OLS and CLS

-- CELL ********************

-- OLS for a Role
GRANT SELECT ON Sales.Orders TO [SalesReps];  

-- OLS to a User 
GRANT SELECT ON Sales.Orders TO [username@company.com];  


-- METADATA ********************

-- META {
-- META   "language": "sql",
-- META   "language_group": "sqldatawarehouse"
-- META }

-- CELL ********************

-- CLS 
GRANT SELECT ON Sales.CustomerDetails 
(CustomerId, AccountCreationDate) 
TO [SalesReps]; 


-- METADATA ********************

-- META {
-- META   "language": "sql",
-- META   "language_group": "sqldatawarehouse"
-- META }

-- MARKDOWN ********************

-- #### Implementing Dynamic Data Masking


-- CELL ********************

CREATE TABLE dbo.EmployeeData (
    EmployeeID INT
    ,FirstName VARCHAR(50) MASKED WITH (FUNCTION = 'partial(1,"-",2)') NULL
    ,LastName VARCHAR(50) MASKED WITH (FUNCTION = 'default()') NULL
    ,SSN CHAR(11) MASKED WITH (FUNCTION = 'partial(0,"XXX-XX-",4)') NULL
    ,email VARCHAR(256) NULL
);

-- METADATA ********************

-- META {
-- META   "language": "sql",
-- META   "language_group": "sqldatawarehouse"
-- META }

-- CELL ********************

-- ALTER TABLE DEFAULT Mask 
ALTER TABLE dbo.EmployeeData 
ALTER COLUMN [FirstName] ADD MASKED WITH (FUNCTION = 'default()');

-- ALTER TABLE EMAIL Mask 
ALTER TABLE dbo.EmployeeData 
ALTER COLUMN [EmployeeEmail] ADD MASKED WITH (FUNCTION = 'email()');

-- ALTER TABLE RANDOM Mask 
ALTER TABLE dbo.EmployeeData 
ALTER COLUMN [Salary] ADD MASKED WITH (FUNCTION = 'random(1,10)');

-- ALTER TABLE PARTIAL Mask 
ALTER TABLE dbo.EmployeeData 
ALTER COLUMN [AccountDetails] ADD MASKED WITH (FUNCTION = 'partial(1,"XXXXX",2)');


-- METADATA ********************

-- META {
-- META   "language": "sql",
-- META   "language_group": "sqldatawarehouse"
-- META }
